+            sigma: vec![0.0; node_count],
+            dist: vec![-1; node_count],
+            delta: vec![0.0; node_count],
+            queue: Vec::with_capacity(node_count),
+        }
+    }
+
+    fn reset(&mut self) {
+        self.stack.clear();
+        self.queue.clear();
+        self.sigma.fill(0.0);
+        self.dist.fill(-1);
+        self.delta.fill(0.0);
+        for preds in &mut self.pred {
+            preds.clear();
+        }
+    }
+}
